def estimate_vram_gb(params_b, quant_bits=16):
    bytes_per_param = quant_bits / 8
    model_gb = params_b * bytes_per_param
    overhead_gb = model_gb * 0.2
    return round(model_gb + overhead_gb, 1)

def find_best_for_gpu(df, vram_gb, quant_bits=4):
    candidates = []
    for _, row in df.iterrows():
        needed = estimate_vram_gb(row["params_b"], quant_bits)
        if needed <= vram_gb:
            candidates.append(row)
    result = pd.DataFrame(candidates)
    return result.nlargest(3, "average")

# Find best models for an 8GB GPU at 4-bit
picks = find_best_for_gpu(df, vram_gb=8, quant_bits=4)
for _, r in picks.iterrows():
    vram = estimate_vram_gb(r["params_b"], 4)
    print(f"{r['model_name']}: avg={r['average']:.1f}, ~{vram}GB")

